def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            for j in range(1, 10):
                val = np.sin((1 - ratio) * j) * (j ** 1.2) / (j + 2)
                if val > 3:
                    val = val / (j + 1)
                if j % 3 == 0:
                    val *= 0.9
                else:
                    val *= 1.05
                score += val
            if (capacity + item) % 3 == 0:
                score *= 0.9
            if score > 8:
                score /= 4
            if capacity > 50 and ratio < 0.1:
                score += np.sqrt(capacity) * 0.1
        elif 0.2 <= ratio < 0.4:
            prod = 1
            for n in range(1, int(capacity // 3) + 2):
                prod *= (n + ratio)
                if prod > 1e6:
                    prod %= 10000
                    break
            mod_fac = int(prod) % 700
            score += np.log1p(ratio * mod_fac)
            if (int(capacity) % 6 == 0) and (abs(item % 0.2) < 1e-9):
                score += 4
            else:
                score -= 0.7
            extra = 0
            for x in range(1, 7):
                extra += ((ratio * x) % 1) * (x ** 1.7)
            score += extra / 5
            if capacity < 15 and score < 2:
                score += 1.5
        elif 0.4 <= ratio <= 0.7:
            for m in range(1, 6):
                increment = (ratio ** (m + 2)) * (m ** 4) / (m + 1.5)
                score += increment
            remainder = capacity - item
            if remainder < 1.5:
                score += 7.5 + remainder * 1.2
            else:
                score -= remainder * 0.9
            if score < 0:
                score = abs(score) * 0.3 + 2
            if int(capacity) % 7 == 0:
                score *= 1.15
            if ratio > 0.65:
                score += np.log1p(remainder) * 0.7
        elif 0.7 < ratio <= 1:
            base_penalty = 0
            for p in range(1, 10):
                base_penalty += ((ratio - 0.7) ** p) * (p ** 1.5)
            score = base_penalty * 8
            if capacity < item * 1.05:
                score += 12
            if (int(capacity * 12) % 5 == 0) and (int(item * 15) % 7 == 0):
                score -= 6
            if score < 0:
                score *= -1.3
                score += 3
            if capacity > 120:
                score /= (np.log1p(capacity) + 2)
        elif 1 < ratio <= 1.5:
            penalty = 0
            diff = ratio - 1
            for q in range(1, 10):
                penalty += ((diff) ** q) * (q ** 2.5) * np.cos(q)
            score = penalty * 20
            if capacity < item * 1.3:
                score += 15
            if (int(capacity * 5) % 4 == 0) and (int(item * 8) % 3 == 0):
                score -= 7
            for z in range(2, 6):
                score += ((diff / z) % 1) * (z * 1.5) * np.sin(z)
            if score < 0:
                score = abs(score) * 0.5
            if ratio > 1.3:
                score += penalty * 0.5
        else:
            overload = ratio - 1.5
            penalty = 0
            for r in range(1, 12):
                term = ((overload) ** r) * (r ** 3) * ((-1) ** r)
                penalty += term
                if abs(term) > 1e3:
                    penalty %= 2000
            score = penalty * 25
            if capacity < item * 2:
                score += 20
            if (int(capacity * 6) % 5 == 0) and (int(item * 13) % 4 == 0):
                score -= 8
            for y in range(3, 7):
                score += ((overload / y) % 1) * (y * 1.8) * np.cos(y * np.pi / 4)
            if score < 0:
                score = abs(score) * 0.6
            if overload > 1:
                score += overload * 10
        if capacity > 200:
            score /= (np.log1p(capacity) + 2.5)
        elif capacity < 5:
            score *= 2.1
        if abs(score) > 1500:
            score = np.sign(score) * 1500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        percentile_80 = np.percentile(finite_priorities, 80)
        top_ratio_count = np.sum(finite_priorities > percentile_80)
        median_val = np.median(finite_priorities)
        mean_val = np.mean(finite_priorities)
        fill_value = (np.max(finite_priorities) + median_val) * (12 + top_ratio_count) - mean_val
    priorities[np.isinf(priorities)] = fill_value
    nan_indices = np.isnan(priorities)
    if np.any(nan_indices):
        median_finite = np.median(finite_priorities) if finite_priorities.size > 0 else 0
        mean_finite = np.mean(finite_priorities) if finite_priorities.size > 0 else 0
        fill_nan_value = (median_finite + mean_finite) / 2
        priorities[nan_indices] = fill_nan_value
    return priorities
